PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdf:  <http://www.w3.org/2000/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX dqv:  <http://www.w3.org/ns/dqv#>
SELECT ?cpath (SUM(?abs) AS ?totalKg) WHERE {
  {
    # Hop 1: top → component
    ?mid1 futuram:refersTo ?comp .
    ?pr1 futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v1 ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
    BIND(1 AS ?depth)
  } UNION {
    # Hop 2: component → material
    ?comp futuram:hasCompositionStatement ?stmt2 .
    ?stmt2 futuram:hasPartRelation ?pr2 .
    ?pr2 futuram:refersTo ?mat ;
         futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v2 ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
    BIND(2 AS ?depth)
  } UNION {
    # Hop 3: material → element
    ?mat futuram:hasCompositionStatement ?stmt3 .
    ?stmt3 futuram:hasPartRelation ?pr3 .
    ?pr3 futuram:refersTo ?elt ;
         futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v3 ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
    BIND(3 AS ?depth)
  }
  {
    <https://www.purl.org/futuram/example#V0401010102_2025> futuram:hasCompositionStatement ?stmt1 .
    ?stmt1 futuram:hasPartRelation ?pr1 .
    ?pr1 futuram:refersTo ?comp .
  }
  ?elt rdf:type <https://www.purl.org/futuram#Copper> .
  BIND(CONCAT(STR(?comp),"|",STR(?mat),"|",STR(?elt)) AS ?cpath)
  BIND(?v1 * ?v2 * ?v3 * 1583.812 AS ?abs)
} GROUP BY ?cpath
ORDER BY DESC(?totalKg)

