  VALUES ?whole { <https://www.purl.org/futuram/example#V0401010102_2025> }
  ?whole futuram:itemMass [ qudt:numericValue ?mass ] .
  <https://www.purl.org/futuram/example#comp_V0401010102_2025> futuram:hasPartRelation ?pr1 .
  ?pr1 futuram:refersTo ?mid ;
        futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v1 ] ;
        dqv:hasQualityMeasurement/dqv:value ?sAcc1 .
  ?mid futuram:hasCompositionStatement ?st2 .
  ?st2 futuram:hasPartRelation ?pr2 .
  ?pr2 futuram:refersTo ?elem ;
